import{_ as s}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as n,e}from"./app-a40c7acb.js";const l={},t=e(`<h1 id="面试-mysql" tabindex="-1"><a class="header-anchor" href="#面试-mysql" aria-hidden="true">#</a> 面试-MySQL</h1><h3 id="索引是什么" tabindex="-1"><a class="header-anchor" href="#索引是什么" aria-hidden="true">#</a> 索引是什么</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：索引是什么</b></summary><p><b style="color:#f19977;">答：索引(index)是帮助数据库高效获取数据的数据结构。MySQL数据库默认采用的是B+Tree的数据结构。其所有的数据都存储在叶子节点，非叶子节点仅用于索引数据。叶子节点形成了一个双向链表，便于数据的排序及区间范围查询。</b></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 创建索引语句</span>
<span class="token keyword">CREATE</span> <span class="token keyword">INDEX</span> 索引名 <span class="token keyword">ON</span> 表名<span class="token punctuation">(</span>列名<span class="token number">1</span><span class="token punctuation">,</span> 列名<span class="token number">2.</span><span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">)</span><span class="token punctuation">;</span>

<span class="token comment">-- 创建表的时候加索引</span>
<span class="token keyword">CREATE</span> <span class="token keyword">TABLE</span> 表名 <span class="token punctuation">(</span>
    列名<span class="token number">1</span> 数据类型<span class="token punctuation">,</span>
    列名<span class="token number">2</span> 数据类型<span class="token punctuation">,</span>
    列名<span class="token number">3</span> 数据类型<span class="token punctuation">,</span>
    <span class="token comment">-- 唯一索引</span>
    <span class="token keyword">UNIQUE</span> <span class="token keyword">KEY</span> 索引名 <span class="token punctuation">(</span>列名<span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">,</span>
    <span class="token comment">-- 普通索引(KEY和INDEX 等价，KEY更简洁)</span>
    <span class="token keyword">KEY</span> 索引名 <span class="token punctuation">(</span>列名<span class="token number">2</span><span class="token punctuation">)</span>
<span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details><h3 id="innodb索引与myisam索引实现的区别" tabindex="-1"><a class="header-anchor" href="#innodb索引与myisam索引实现的区别" aria-hidden="true">#</a> InnoDB索引与MYISAM索引实现的区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：InnoDB索引与MYISAM索引实现的区别</b></summary><p><b style="color:#f19977;">答：InnoDB是聚簇索引(数据即索引)，MyISAM 是非聚簇索引(索引与数据分离)。两者底层都用B+Tree。如果是主键查询则InnoDB只需一次B+Tree查找然后直接取数据，而MYISAM的索引与数据是不同的文件会先在索引文件中查其在数据文件中的位置然后再从数据文件中取出数据。</b></p></details><h3 id="聚簇索引与非聚簇索引" tabindex="-1"><a class="header-anchor" href="#聚簇索引与非聚簇索引" aria-hidden="true">#</a> 聚簇索引与非聚簇索引</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：聚簇索引与非聚簇索引</b></summary><p><b style="color:#f19977;">答：聚簇索引：数据与索引放到一块，B+Tree树的叶子节点保存了整行数据。<br>非聚簇索引(二级索引)：数据与索引分开，B+Tree的叶子节点保存对应的主键，要想获取数据需要先走非聚簇索引获取对应主键，再根据主键走聚簇索引获取整行数据即回表操作。</b></p></details><h3 id="覆盖索引与非覆盖索引" tabindex="-1"><a class="header-anchor" href="#覆盖索引与非覆盖索引" aria-hidden="true">#</a> 覆盖索引与非覆盖索引</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：覆盖索引与非覆盖索引</b></summary><p><b style="color:#f19977;">答：覆盖索引：指查询使用了索引，并且需要返回的列，在该索引中已经全部能够找到。比如只给name字段和age字段增加了索引，返回的列只有name或者只有age或者既有name也有age就是覆盖索引。如果返回的列有address等其它字段就是非覆盖索引则查询数据时需要多一步回表查询。</b></p></details><h3 id="mysql超大分页怎么处理" tabindex="-1"><a class="header-anchor" href="#mysql超大分页怎么处理" aria-hidden="true">#</a> MySQL超大分页怎么处理</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：MySQL超大分页怎么处理</b></summary><p><b style="color:#f19977;">答：在数据量比较大时，limit分页查询，需要对数据进行排序，效率低。解决方案：覆盖索引 + 子查询</b></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 原SQL</span>
<span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> tb_sku <span class="token keyword">limit</span> <span class="token number">9000000</span><span class="token punctuation">,</span> <span class="token number">10</span>

<span class="token comment">-- 优化后</span>
<span class="token keyword">select</span>
	a<span class="token punctuation">.</span><span class="token operator">*</span>
<span class="token keyword">from</span> 
	tb_sku <span class="token keyword">as</span> a<span class="token punctuation">,</span>
<span class="token keyword">inner</span> <span class="token keyword">join</span>
	<span class="token punctuation">(</span><span class="token keyword">select</span> id <span class="token keyword">from</span> tb_sku <span class="token keyword">order</span> <span class="token keyword">by</span> id <span class="token keyword">limit</span> <span class="token number">9000000</span><span class="token punctuation">,</span> <span class="token number">10</span><span class="token punctuation">)</span> <span class="token keyword">as</span> b
<span class="token keyword">on</span> a<span class="token punctuation">.</span>id <span class="token operator">=</span> b<span class="token punctuation">.</span>id
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details><h3 id="mysql为什么使用b-tree作为索引结构" tabindex="-1"><a class="header-anchor" href="#mysql为什么使用b-tree作为索引结构" aria-hidden="true">#</a> MySQL为什么使用B+Tree作为索引结构</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：MySQL为什么使用B+Tree作为索引结构</b></summary><p><b style="color:#f19977;">答：B树是一种多路平衡树，用其存储大量数据，整个树的高度相比二叉树来说会矮很多。树的高度决定磁盘IO的次数，树越矮，次数越少就越快。<br>相比较与B树，B+Tree所有的数据都存储在叶子节点并且使用双向链表的方式进行关联，非叶子节点只存储索引。B+Tree非叶子节点不存储数据，所以每一层能够存储的索引数量会增加，意味着B+树在层高相同的情况下存储的数据量要比B树要多，使得磁盘IO次数更少。<br>在MySQL里面，范围查询是一个比较常用的操作，而B+Tree的所有存储在叶子节点的数据使用了双向链表来关联，所以在查询的时候只需查两个节点进行遍历就行，而B树需要获取所有节点，所以B+Tree在范围查询上效率更高。<br>因为B+Tree叶子节点存储所有数据，所以B+Tree的全局扫描能力更强一些，因为它只需要扫描叶子节点。但是B树需要遍历整个树。</b></p></details><h3 id="为什么建议使用自增长主键作为索引" tabindex="-1"><a class="header-anchor" href="#为什么建议使用自增长主键作为索引" aria-hidden="true">#</a> 为什么建议使用自增长主键作为索引</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：为什么建议使用自增长主键作为索引</b></summary><p><b style="color:#f19977;">答：自增主键能够维持底层数据顺序写入，顺序写入比随机写入快很多<br>读取可以由B+Tree树的二分查找定位<br>支持范围查找，范围数据自带顺序</b></p></details><h3 id="索引失效场景" tabindex="-1"><a class="header-anchor" href="#索引失效场景" aria-hidden="true">#</a> 索引失效场景</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：索引失效场景</b></summary><p><b style="color:#f19977;">答：使用函数或者计算导致索引失效<br>like以%开头导致索引失效<br>不等于导致索引失效<br>类型转换导致索引失效</b></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 使用函数导致索引失效</span>
<span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> emp <span class="token keyword">where</span> <span class="token keyword">left</span><span class="token punctuation">(</span>name<span class="token punctuation">,</span> <span class="token number">3</span><span class="token punctuation">)</span> <span class="token operator">=</span> <span class="token string">&#39;abc&#39;</span>

<span class="token comment">-- like以%开头导致索引失效</span>
<span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> emp <span class="token keyword">where</span> name <span class="token operator">like</span> <span class="token string">&#39;%ab%&#39;</span>

<span class="token comment">-- 不等于导致索引失效</span>
<span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> emp <span class="token keyword">where</span> name <span class="token operator">&lt;&gt;</span> <span class="token string">&#39;abc&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details><h3 id="like以-开头会导致索引一定失效吗" tabindex="-1"><a class="header-anchor" href="#like以-开头会导致索引一定失效吗" aria-hidden="true">#</a> like以%开头会导致索引一定失效吗？</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：like以%开头会导致索引一定失效吗？</b></summary><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 非覆盖索引会失效</span>
<span class="token keyword">select</span> <span class="token operator">*</span> <span class="token keyword">from</span> <span class="token keyword">user</span> <span class="token keyword">where</span> name <span class="token operator">like</span> <span class="token string">&#39;%三&#39;</span>

<span class="token comment">-- 覆盖索引不会失效</span>
<span class="token keyword">select</span> name <span class="token keyword">from</span> <span class="token keyword">user</span> <span class="token keyword">where</span> name <span class="token operator">like</span> <span class="token string">&#39;%三&#39;</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details><h3 id="count-和count-列名-有什么区别" tabindex="-1"><a class="header-anchor" href="#count-和count-列名-有什么区别" aria-hidden="true">#</a> count(*)和count(列名)有什么区别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：count(*)和count(列名)有什么区别</b></summary><p><b style="color:#f19977;">答：count(*)会统计值为null的行<br>count(列名)不会统计值为null的行</b></p></details><h3 id="日常工作中怎么优化sql" tabindex="-1"><a class="header-anchor" href="#日常工作中怎么优化sql" aria-hidden="true">#</a> 日常工作中怎么优化SQL</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：日常工作中怎么优化SQL</b></summary><p><b style="color:#f19977;">答：加索引<br>减少返回的数据列<br>避免走全表扫描、避免子查询<br>分库分表</b></p></details><h3 id="如何定位慢查询" tabindex="-1"><a class="header-anchor" href="#如何定位慢查询" aria-hidden="true">#</a> 如何定位慢查询</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：如何定位慢查询</b></summary><p><b style="color:#f19977;">答：使用外部工具监控接口，查看接口调用时间。也可以使用MySQL自带的慢日志查询，其能记录所有执行时间超过指定参数的所有SQL语句日志，MySQL默认不开启慢查询日志，需要自己配置开启。</b></p></details><h3 id="sql语句执行很慢-如何分析" tabindex="-1"><a class="header-anchor" href="#sql语句执行很慢-如何分析" aria-hidden="true">#</a> SQL语句执行很慢，如何分析</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：SQL语句执行很慢，如何分析</b></summary><p><b style="color:#f19977;">答：在select语句之前加上关键字explain可以查看SQL语句的执行计划，可以看这条SQL有没有走索引、是否存在全盘扫描等等</b></p></details><h3 id="事务的四大特性" tabindex="-1"><a class="header-anchor" href="#事务的四大特性" aria-hidden="true">#</a> 事务的四大特性</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：事务的四大特性</b></summary><p><b style="color:#f19977;">答：事务是一组操作的集合，它是一个不可分割的工作单位，事务会把所有的操作作为一个整体一起向系统提交或撤销操作请求，即这些操作要么同时成功，要么同时失败。<br>原子性：事务是不可分割的最小操作单位，要么全部成功，要么全部失败<br>一致性：事务完成时，必须使所有的数据都保持一致状态<br>隔离性：数据库系统提供的隔离机制，保证事务在不受外部并发操作影响下的独立环境下运行<br>持久性：事务一旦提交或回滚，它对数据库中的数据改变就是永久的</b></p></details><h3 id="并发事务带来的问题" tabindex="-1"><a class="header-anchor" href="#并发事务带来的问题" aria-hidden="true">#</a> 并发事务带来的问题</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：并发事务带来的问题</b></summary><p><b style="color:#f19977;">答：脏读：一个事务读取到另外一个事务还没有提交的数据<br>不可重复读：一个事务先后读取同一条记录，但两次读取的数据不同<br>幻读：一个事务按照条件查询数据时，没有对应的数据行，但是在插入数据行时又发现这行数据已经存在</b></p></details><h3 id="mysql默认隔离级别" tabindex="-1"><a class="header-anchor" href="#mysql默认隔离级别" aria-hidden="true">#</a> MySQL默认隔离级别</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：MySQL默认隔离级别</b></summary><p><b style="color:#f19977;">答：隔离级别：读未提交(什么都不能解决)、读已提交(能解决脏读)、可重复读(MySQL默认，能解决脏读、不可重复读)、串行化(能解决脏读、不可重复读、幻读)。</b></p></details><h3 id="mysql主从同步原理" tabindex="-1"><a class="header-anchor" href="#mysql主从同步原理" aria-hidden="true">#</a> MySQL主从同步原理</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：MySQL主从同步原理</b></summary><p><b style="color:#f19977;">答：MySQL主从复制的核心就是二进制日志BinLog文件，主库在事务提交时，会把数据变更记录在二进制日志文件binlog中，从库读取主库的binlog文件，写入到从库的中继日志Relay Log文件中，从库重做中继日志中的事件，将改变反映它自己的数据。</b></p></details><h3 id="数据库连接池有什么用" tabindex="-1"><a class="header-anchor" href="#数据库连接池有什么用" aria-hidden="true">#</a> 数据库连接池有什么用</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：数据库连接池有什么用</b></summary><p><b style="color:#f19977;">答：首先，数据库连接池是一种池化技术，池化技术的核心思想是实现资源的复用，避免资源重复创建销毁的开销。而在数据库的应用场景里面，应用程序每次向数据库发起CRUD操作的时候，都需要创建连接。在数据库访问量较大的情况下，频繁的创建连接会带来较大的性能开销。而连接池的核心思想，就是应用程序在启动的时候提前初始化一部分连接保存到连接池里面，当应用需要使用连接的时候，直接从连接池获取一个已经建立好的链接。避免了每次连接的建立和释放带来的开销。</b></p></details><h3 id="数据库连接池有哪些关键参数" tabindex="-1"><a class="header-anchor" href="#数据库连接池有哪些关键参数" aria-hidden="true">#</a> 数据库连接池有哪些关键参数</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：数据库连接池有哪些关键参数</b></summary><p><b style="color:#f19977;">答：初始化连接数、最大连接数、最大空闲连接数、最小空闲连接、最大等待时间、无效连接清除</b></p></details>`,39),r=[t];function i(o,c){return a(),n("div",null,r)}const u=s(l,[["render",i],["__file","面试-MySQL.html.vue"]]);export{u as default};
